### src/auth/session.service.ts
@@ -1,18 +1,32 @@
 import { Injectable } from '@nestjs/common';
 import { TokenService } from './token.service';
 import { SessionStore } from './session.store';
+import { UserRiskScorer } from '../security/user-risk-scorer';

 @Injectable()
 export class SessionService {
-  async createSession(userId: string): Promise<string> {
-    const token = this.tokenService.generate(userId);
-    await this.store.save(userId, token);
-    return token;
+  async createSession(userId: string, metadata: SessionMetadata): Promise<SessionResult> {
+    const riskScore = await this.riskScorer.evaluate(userId, metadata.ip, metadata.deviceFingerprint);
+    const tokenTtl = riskScore > 0.7 ? 900 : 3600;
+    const token = this.tokenService.generate(userId, { ttl: tokenTtl, scope: metadata.scope });
+    await this.store.save(userId, { token, riskScore, createdAt: Date.now(), expiresAt: Date.now() + tokenTtl * 1000 });
+    if (riskScore > 0.9) await this.notifySecurityTeam(userId, riskScore, metadata);
+    return { token, expiresIn: tokenTtl, riskLevel: riskScore > 0.7 ? 'high' : 'normal' };
   }

-  async revokeSession(userId: string): Promise<void> {
-    await this.store.delete(userId);
+  async revokeSession(userId: string, reason: RevokeReason): Promise<void> {
+    const session = await this.store.get(userId);
+    if (session) {
+      await this.tokenService.blacklist(session.token);
+      await this.store.delete(userId);
+      await this.auditLog.record('session_revoked', { userId, reason });
+    }
   }
 }

